============================ DROP-IN START ============================

.crdk-home{
--cr-accent: #0947c2;
--cr-accent-strong: #073aa0;
--cr-accent-ink: #ffffff;
--cr-accent-tint: #eef4fb;
--cr-surface: #ffffff;
--cr-border: #e3e8ef;
--cr-text: #14202e;
--cr-muted: #5b6b7d;
--cr-radius: 16px;
--cr-radius-sm: 11px;
color:var(--cr-text);
font-family:"Lato", Arial, sans-serif;
line-height:1.55;
max-width:1080px;
margin:0 auto;
}
.crdk-home *{ box-sizing:border-box; }
.crdk-home a{ color:var(--cr-accent); text-decoration:none; }
.crdk-home a:hover{ text-decoration:underline; }
.crdk-home .btn{
display:inline-flex;
align-items:center;
gap:8px;
font-family:"Lato", Arial, sans-serif;
font-weight:700;
font-size:15px;
line-height:1.2;
padding:13px 22px;
border-radius:var(--cr-radius-sm);
border:1px solid transparent;
cursor:pointer;
transition:background .15s,border-color .15s,color .15s;
text-decoration:none;
}
.crdk-home .btn:hover{ text-decoration:none; }
.crdk-home .btn-primary{ background:var(--cr-accent); color:var(--cr-accent-ink); }
.crdk-home .btn-primary:hover{ background:var(--cr-accent-strong); }
.crdk-home .btn-ghost{ background:var(--cr-surface); color:var(--cr-text); border-color:var(--cr-border); }
.crdk-home .btn-ghost:hover{ border-color:var(--cr-accent); color:var(--cr-accent); }
.crdk-home .btn-onaccent{ background:#fff; color:var(--cr-accent-strong); }
.crdk-home .btn-onaccent:hover{ background:#f3f7fc; }
.crdk-home .hero{
text-align:center;
padding:8px 8px 4px;
max-width:760px;
margin:0 auto;
}
.crdk-home h1{
font-size:clamp(28px,4.2vw,44px);
line-height:1.1;
letter-spacing:-.015em;
font-weight:700;
margin:18px 0 0;
}
.crdk-home .sub{
font-size:clamp(15px,1.8vw,18px);
color:var(--cr-muted);
margin:16px auto 0;
max-width:60ch;
}
.crdk-home .proof{
display:inline-block;
margin-top:20px;
font-size:13.5px;
line-height:1.5;
color:var(--cr-text);
background:var(--cr-accent-tint);
border:1px solid var(--cr-border);
border-radius:12px;
padding:11px 18px;
max-width:58ch;
text-align:center;
text-wrap:balance;
}
.crdk-home .proof b{
color:var(--cr-accent-strong);
font-weight:700;
}
.crdk-home .proof .sep{
margin:0 9px;
color:var(--cr-muted);
}
.crdk-home .proof .cmp{ white-space:nowrap; }
.crdk-home .proof a{ font-weight:600; white-space:nowrap; }
.crdk-home .hero-ctas{
display:flex;
flex-wrap:wrap;
gap:12px;
justify-content:center;
margin-top:24px;
}
.crdk-home .props{
display:grid;
grid-template-columns:repeat(3,1fr);
gap:16px;
margin-top:38px;
}
@media (max-width:760px){
.crdk-home .props{ grid-template-columns:1fr; }
}
.crdk-home .prop{
background:var(--cr-surface);
border:1px solid var(--cr-border);
border-radius:var(--cr-radius);
padding:20px;
}
.crdk-home .prop .ic{
width:38px;
height:38px;
border-radius:10px;
background:var(--cr-accent-tint);
display:flex;
align-items:center;
justify-content:center;
color:var(--cr-accent);
margin-bottom:12px;
}
.crdk-home .prop h3{
margin:0 0 6px;
font-size:16px;
font-weight:700;
}
.crdk-home .prop p{
margin:0;
font-size:14px;
color:var(--cr-muted);
}
.crdk-home .banner{
margin-top:34px;
background:var(--cr-accent);
color:var(--cr-accent-ink);
border-radius:var(--cr-radius);
padding:clamp(22px,3vw,32px);
display:flex;
flex-wrap:wrap;
align-items:center;
gap:20px 28px;
justify-content:space-between;
background-image:linear-gradient(135deg, var(--cr-accent) 0%, var(--cr-accent-strong) 100%);
}
.crdk-home .banner .b-text{
flex:1 1 340px;
min-width:280px;
}
.crdk-home .banner .b-tag{
font-size:11.5px;
font-weight:600;
letter-spacing:.08em;
text-transform:uppercase;
opacity:.85;
}
.crdk-home .banner h2{
margin:8px 0 6px;
font-size:clamp(20px,2.6vw,27px);
font-weight:700;
line-height:1.15;
}
.crdk-home .banner p{
margin:0;
font-size:14.5px;
opacity:.92;
max-width:52ch;
}
.crdk-home .banner .b-actions{
display:flex;
flex-direction:column;
gap:10px;
align-items:flex-start;
}
.crdk-home .banner .b-actions .sub-link{
color:#fff;
opacity:.9;
font-size:13px;
text-decoration:underline;
}
.crdk-home .ai{
margin-top:34px;
background:var(--cr-surface);
border:1px solid var(--cr-border);
border-radius:var(--cr-radius);
padding:clamp(22px,3vw,34px);
}
.crdk-home .ai .new{
display:inline-flex;
align-items:center;
gap:7px;
font-size:11.5px;
font-weight:700;
letter-spacing:.06em;
text-transform:uppercase;
color:var(--cr-accent);
background:var(--cr-accent-tint);
border-radius:999px;
padding:6px 13px;
}
.crdk-home .ai h2{
font-size:clamp(22px,3vw,30px);
line-height:1.15;
font-weight:700;
letter-spacing:-.01em;
margin:16px 0 0;
max-width:24ch;
}
.crdk-home .ai .intro{
font-size:15px;
color:var(--cr-muted);
margin:12px 0 0;
max-width:64ch;
}
.crdk-home .steps{
display:grid;
grid-template-columns:repeat(3,1fr);
gap:16px;
margin:24px 0 0;
}
@media (max-width:760px){
.crdk-home .steps{ grid-template-columns:1fr; }
}
.crdk-home .step{
border:1px solid var(--cr-border);
border-radius:var(--cr-radius-sm);
padding:16px;
}
.crdk-home .step .n{
font-weight:700;
font-size:12px;
color:var(--cr-accent);
font-variant-numeric:tabular-nums;
}
.crdk-home .step b{
display:block;
margin:6px 0 4px;
font-size:14.5px;
}
.crdk-home .step p{
margin:0;
font-size:13px;
color:var(--cr-muted);
}
.crdk-home .ai-note{
margin:20px 0 0;
font-size:13.5px;
color:var(--cr-text);
background:var(--cr-accent-tint);
border:1px solid var(--cr-border);
border-left:3px solid var(--cr-accent);
border-radius:var(--cr-radius-sm);
padding:12px 15px;
}
.crdk-home .ai-ctas{
display:flex;
flex-wrap:wrap;
gap:12px;
margin-top:20px;
}
.crdk-home .ai .pricing{
margin:14px 0 0;
font-size:12px;
color:var(--cr-muted);
}
/* Match new buttons with old Stackable buttons */
.crdk-home .btn,
.ugb-c553d17 .ugb-button {
min-height: 58px !important;
padding: 16px 28px !important;
border-radius: 14px !important;
font-family: "Lato", Arial, sans-serif !important;
font-size: 18px !important;
font-weight: 700 !important;
line-height: 1.2 !important;
display: inline-flex !important;
align-items: center !important;
justify-content: center !important;
}
.crdk-home .btn,
.ugb-c553d17 .ugb-button--inner {
font-family: "Lato", Arial, sans-serif !important;
font-size: 18px !important;
font-weight: 700 !important;
line-height: 1.2 !important;
}

